proof_block:
// Bring the two ensures-instances into the proof context so the SMT solver
// can chain them by transitivity at the SingleMessage<Message> level.
assert(r1@ == self_@);
assert(r2@ == self_@);
assert(r1@ == r2@);

// Case-split on the variants of r1 / r2 so that Verus can use ADT
// constructor injectivity on the view to align the underlying CSingleMessage
// constructors and fields.
match r1 {
    CSingleMessage::Message { seqno: s1, dst: d1, m: m1 } => {
        match r2 {
            CSingleMessage::Message { seqno: s2, dst: d2, m: m2 } => {
                // Constructor of SingleMessage::Message is injective, so the
                // (nat-casted) seqno, the EndPoint view and the CMessage view
                // must all coincide between r1 and r2.
                assert(s1 as nat == s2 as nat);
                assert(s1 == s2);
                assert(d1@ == d2@);
                assert(d1.id@ == d2.id@);
                assert(m1@ == m2@);
            }
            CSingleMessage::Ack { ack_seqno: _ } => { assert(false); }
            CSingleMessage::InvalidMessage {} => { assert(false); }
        }
    }
    CSingleMessage::Ack { ack_seqno: a1 } => {
        match r2 {
            CSingleMessage::Ack { ack_seqno: a2 } => {
                assert(a1 as nat == a2 as nat);
                assert(a1 == a2);
            }
            CSingleMessage::Message { .. } => { assert(false); }
            CSingleMessage::InvalidMessage {} => { assert(false); }
        }
    }
    CSingleMessage::InvalidMessage {} => {
        match r2 {
            CSingleMessage::InvalidMessage {} => {}
            CSingleMessage::Message { .. } => { assert(false); }
            CSingleMessage::Ack { ack_seqno: _ } => { assert(false); }
        }
    }
}
